(function(){var modal=document.getElementById("trailerModal");var slot=document.getElementById("trailerSlot");var title=document.getElementById("trailerTitle");var closeBtn=document.getElementById("trailerClose");if(!modal||!slot)return;var lastFocus=null;function open(url,gameTitle){lastFocus=document.activeElement;title.textContent=gameTitle||"Trailer";if(/\.(mp4|webm|mov)(\?|$)/i.test(url)){slot.innerHTML='<video src="'+url+'" controls autoplay playsinline></video>'}else{var src=url+(url.indexOf("?")>-1?"&":"?")+"autoplay=1&rel=0";slot.innerHTML='<iframe src="'+src+'" title="'+(gameTitle||"Trailer")+' trailer" allow="autoplay; encrypted-media; picture-in-picture" allowfullscreen></iframe>'}modal.classList.add("is-open");modal.setAttribute("aria-hidden","false");document.body.classList.add("has-trailer");document.dispatchEvent(new CustomEvent("trailer:open"));requestAnimationFrame(function(){closeBtn.focus()})}function close(){modal.classList.remove("is-open");modal.setAttribute("aria-hidden","true");document.body.classList.remove("has-trailer");slot.innerHTML="";document.dispatchEvent(new CustomEvent("trailer:close"));if(lastFocus&&lastFocus.focus)lastFocus.focus()}document.addEventListener("click",function(e){var btn=e.target.closest(".btn-trailer");if(btn){e.preventDefault();open(btn.dataset.trailer,btn.dataset.trailerTitle);return}if(modal.classList.contains("is-open")&&e.target===modal){close()}});closeBtn.addEventListener("click",close);document.addEventListener("keydown",function(e){if(e.key==="Escape"&&modal.classList.contains("is-open")){close()}})})();
